     1→import React, { useState } from "react";
     2→
     3→export default function JobsForm() {
     4→  const [formValue, setFormValue] = useState({ email: "" });
     5→  const [formError, setFormError] = useState({});
     6→  const [submit, setSubmit] = useState(false);
     7→  const [loading, setLoading] = useState(false);
     8→
     9→  const handleSubmit = async (e) => {
    10→    e.preventDefault();
    11→    setLoading(true);
    12→    setFormError(validateForm(formValue));
    13→    if (Object.keys(validateForm(formValue)).length > 0) {
    14→      setLoading(false);
    15→      return null;
    16→    } else {
    17→      setSubmit(true);
    18→      setFormValue({ email: "" });
    19→      setLoading(false);
    20→    }
    21→  };
    22→  const handleValidation = (e) => {
    23→    const { name, value } = e.target;
    24→    setFormValue({ ...formValue, [name]: value });
    25→  };
    26→
    27→  const validateForm = (value) => {
    28→    const errors = {};
    29→    const emailValidation = /^\w+([.-]?\w+)*@\w+([.-]?\w+)*(\.\w{2,3})+$/;
    30→    if (!value.email) {
    31→      errors.email = "Empty email field";
    32→    } else if (!emailValidation.test(value.email)) {
    33→      errors.email = "Invalid email format";
    34→    }
    35→    return errors;
    36→  };
    37→  return (
    38→    <article className="max-w-7xl mx-auto py-12 px-4 sm:px-6 lg:py-16 lg:px-8">
    39→      <h2 className=" text-3xl font-extrabold tracking-tight text-white sm:block sm:text-4xl">
    40→        Ready to advance your career?
    41→      </h2>
    42→      <p className=" text-3xl font-extrabold tracking-tight text-[color:var(--primary-font-color)] sm:block sm:text-4xl">
    43→        Send us your email and we will contact you.
    44→      </p>
    45→      {loading ? (
    46→        <React.Fragment>
    47→          <div role="status">
